        if not old_messages:
            print(f"{YELLOW}  ⚠ 没有足够的旧消息可压缩{RESET}\n")
            return True
        summary_prompt = [
            {"role": "system", "content": "请用中文简洁总结以下对话的要点，包括：用户的主要请求、已完成的操作、关键决策和结果。不超过 500 字。"},
