def _resolve_start_path(usecwd: bool) -> str:
    """
    Determine the directory from which to start searching for .env files.

    When running interactively (REPL, notebook), in a debugger, in a frozen
    application, or when *usecwd* is True, the current working directory is
    used.  Otherwise the directory of the calling module's source file is used.
    """
    if usecwd or _is_interactive() or _is_debugger() or getattr(sys, "frozen", False):
        return os.getcwd()

